peak_sql:
SELECT AVG(duration_min) AS avg_duration_min
FROM `demo.trips.rides`
WHERE EXTRACT(YEAR FROM ride_date) = 2026;

SELECT COUNT(*) AS active_members
FROM `demo.dim.members`
WHERE status = 'active';

WITH per_member AS (
  SELECT member_id, SUM(fare) AS total_fare
  FROM `demo.trips.rides`
  GROUP BY member_id
)
SELECT * FROM per_member ORDER BY total_fare DESC LIMIT 100;
